import React, { useState } from 'react';
import { InstagramIcon, WhatsAppIcon } from '../constants';

const ContactSection: React.FC = () => {
  const [formState, setFormState] = useState({
    name: '',
    email: '',
    message: '',
    type: 'clase',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormState(prevState => ({ ...prevState, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // In a real app, you would handle form submission here
    alert('Gracias por tu mensaje. Nos pondremos en contacto contigo pronto.');
    setFormState({ name: '', email: '', message: '', type: 'clase' });
  };

  return (
    <section id="contacto" className="py-20 md:py-32 bg-emerald-50/50">
      <div className="container mx-auto px-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-16 items-center">
          <div>
            <h2 className="text-4xl md:text-5xl font-['Cormorant_Garamond'] text-emerald-900 font-semibold mb-6">Ubicación y Contacto</h2>
            <p className="text-stone-600 mb-6">
              Nos encontramos en Candelaria Trv 1 #17-29. ¡Ven y visítanos!
            </p>
            <div className="h-80 rounded-lg overflow-hidden shadow-lg">
              <iframe
                src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3976.999516805844!2d-74.068923685238!3d4.593718996660161!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x8e3f99a6f1d2b7f3%3A0x63d3b3c3b0f025e1!2sCra.%201%20%2317-29%2C%20Bogot%C3%A1!5e0!3m2!1sen!2sco!4v1668812345678"
                width="100%"
                height="100%"
                style={{ border: 0 }}
                allowFullScreen={true}
                loading="lazy"
                referrerPolicy="no-referrer-when-downgrade"
              ></iframe>
            </div>
            <div className="flex space-x-4 mt-6">
              <a href="#" className="text-stone-600 hover:text-emerald-800 transition-colors"><InstagramIcon /></a>
              <a href="#" className="text-stone-600 hover:text-emerald-800 transition-colors"><WhatsAppIcon /></a>
            </div>
          </div>
          <div className="bg-white p-8 rounded-lg shadow-xl">
            <h3 className="text-2xl font-semibold mb-6 text-stone-800">Envíanos un mensaje</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <input type="text" name="name" value={formState.name} onChange={handleInputChange} placeholder="Nombre" className="w-full p-3 border border-stone-300 rounded-md focus:ring-emerald-500 focus:border-emerald-500" required />
              <input type="email" name="email" value={formState.email} onChange={handleInputChange} placeholder="Email" className="w-full p-3 border border-stone-300 rounded-md focus:ring-emerald-500 focus:border-emerald-500" required />
              <select name="type" value={formState.type} onChange={handleInputChange} className="w-full p-3 border border-stone-300 rounded-md focus:ring-emerald-500 focus:border-emerald-500 bg-white">
                <option value="clase">Consulta de Clase</option>
                <option value="evento">Consulta de Evento</option>
                <option value="producto">Consulta de Producto</option>
                <option value="otro">Otro</option>
              </select>
              <textarea name="message" value={formState.message} onChange={handleInputChange} placeholder="Mensaje" rows={4} className="w-full p-3 border border-stone-300 rounded-md focus:ring-emerald-500 focus:border-emerald-500" required></textarea>
              <button type="submit" className="w-full bg-emerald-700 hover:bg-emerald-800 text-white font-semibold py-3 rounded-md transition-colors">Enviar</button>
