import React, { createContext, useState, ReactNode } from 'react';
import type { CartItem, BookingDetails, CartItemType } from '../types';

interface CartContextType {
  cart: CartItem[];
  addToCart: (item: CartItem) => void;
  removeFromCart: (itemId: string) => void;
  clearCart: () => void;
  isBookingModalOpen: boolean;
  bookingDetails: BookingDetails | null;
  openBookingModal: (details: BookingDetails) => void;
  closeBookingModal: () => void;
  isCheckoutModalOpen: boolean;
  toggleCheckoutModal: () => void;
}

export const CartContext = createContext<CartContextType>({} as CartContextType);

export const CartProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isBookingModalOpen, setIsBookingModalOpen] = useState(false);
  const [bookingDetails, setBookingDetails] = useState<BookingDetails | null>(null);
  const [isCheckoutModalOpen, setIsCheckoutModalOpen] = useState(false);

  const addToCart = (item: CartItem) => {
    setCart((prevCart) => {
      const existingItem = prevCart.find((i) => i.id === item.id);
      if (existingItem) {
        return prevCart.map((i) =>
          i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
        );
      }
      return [...prevCart, item];
    });
  };

  const removeFromCart = (itemId: string) => {
    setCart((prevCart) => prevCart.filter((item) => item.id !== itemId));
  };

  const clearCart = () => {
    setCart([]);
  };

  const openBookingModal = (details: BookingDetails) => {
    setBookingDetails(details);
    setIsBookingModalOpen(true);
  };

  const closeBookingModal = () => {
    setIsBookingModalOpen(false);
    setBookingDetails(null);
  };

  const toggleCheckoutModal = () => {
    setIsCheckoutModalOpen(prev => !prev);
  }

  return (
    <CartContext.Provider
      value={{
        cart,
        addToCart,
        removeFromCart,
        clearCart,
        isBookingModalOpen,
        bookingDetails,
        openBookingModal,
        closeBookingModal,
        isCheckoutModalOpen,
        toggleCheckoutModal,
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

import React, { useContext, useState } from 'react';
import { CartContext } from '../context/CartContext';
import { CloseIcon } from '../constants';

const availableTimeSlots = [
    'Lunes, 10:00 AM',
    'Miércoles, 6:00 PM',
    'Viernes, 9:00 AM',
    'Sábado, 11:00 AM',
];

const BookingModal: React.FC = () => {
  const { isBookingModalOpen, closeBookingModal, bookingDetails, addToCart } = useContext(CartContext);
  const [selectedSlot, setSelectedSlot] = useState<string | null>(availableTimeSlots[0]);

  if (!isBookingModalOpen || !bookingDetails) return null;

  const handleAddToCart = () => {
    if (selectedSlot) {
        addToCart({
            id: `${bookingDetails.type}-${bookingDetails.title}-${selectedSlot}`,
            name: bookingDetails.title,
            price: bookingDetails.price,
            imageUrl: bookingDetails.imageUrl,
            quantity: 1,
            type: bookingDetails.type,
            details: selectedSlot
        });
        closeBookingModal();
    } else {
        alert("Por favor, selecciona un horario.");
    }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4">
      <div className="bg-white rounded-lg shadow-2xl w-full max-w-md relative animate-fade-in-up">
        <button onClick={closeBookingModal} className="absolute top-4 right-4 text-stone-500 hover:text-stone-800">
          <CloseIcon className="w-6 h-6" />
        </button>
        <div className="p-8">
          <h2 className="text-3xl font-['Cormorant_Garamond'] text-stone-800 font-bold mb-4">Reservar: {bookingDetails.title}</h2>
          <img src={bookingDetails.imageUrl} alt={bookingDetails.title} className="w-full h-48 object-cover rounded-lg mb-6"/>

          <h3 className="text-lg font-semibold text-stone-700 mb-3">Selecciona un horario:</h3>
          <div className="space-y-2">
            {availableTimeSlots.map(slot => (
                 <label key={slot} className={`flex items-center p-3 border rounded-md cursor-pointer transition-colors ${selectedSlot === slot ? 'bg-amber-100 border-amber-500' : 'border-stone-200 hover:bg-stone-50'}`}>
                    <input type="radio" name="time-slot" value={slot} checked={selectedSlot === slot} onChange={() => setSelectedSlot(slot)} className="form-radio text-amber-600 focus:ring-amber-500 h-4 w-4"/>
                    <span className="ml-3 text-stone-700">{slot}</span>
                </label>
            ))}
          </div>

          <div className="mt-8 flex justify-between items-center">
            <p className="text-2xl font-bold text-emerald-800">${bookingDetails.price.toFixed(2)}</p>
            <button onClick={handleAddToCart} className="bg-emerald-700 hover:bg-emerald-800 text-white font-semibold py-3 px-8 rounded-full transition-all duration-300 transform hover:scale-105">
                Confirmar y Añadir
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BookingModal;

import React, { useContext } from 'react';
import { CartContext } from '../context/CartContext';
import { CloseIcon } from '../constants';

const CheckoutModal: React.FC = () => {
    const { isCheckoutModalOpen, toggleCheckoutModal, cart, removeFromCart, clearCart } = useContext(CartContext);
    const totalPrice = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

    if (!isCheckoutModalOpen) return null;

    const handlePayment = (e: React.FormEvent) => {
        e.preventDefault();
        alert('¡Gracias por tu compra! Tu pago ha sido procesado exitosamente.');
        clearCart();
        toggleCheckoutModal();
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-50 flex justify-center items-start p-4 overflow-y-auto">
            <div className="bg-stone-50 rounded-lg shadow-2xl w-full max-w-lg relative my-8 animate-fade-in-up">
                <div className="sticky top-0 bg-stone-50 p-6 border-b border-stone-200 flex justify-between items-center rounded-t-lg">
                    <h2 className="text-3xl font-['Cormorant_Garamond'] text-stone-800 font-bold">Tu Carrito</h2>
                    <button onClick={toggleCheckoutModal} className="text-stone-500 hover:text-stone-800">
                        <CloseIcon className="w-6 h-6" />
                    </button>
                </div>

                <div className="p-6">
                    {cart.length === 0 ? (
                        <p className="text-center text-stone-500 py-12">Tu carrito está vacío.</p>
                    ) : (
                        <>
                            <div className="space-y-4 mb-6 max-h-60 overflow-y-auto pr-2">
                                {cart.map(item => (
                                    <div key={item.id} className="flex items-center justify-between">
                                        <div className="flex items-center space-x-4">
                                            <img src={item.imageUrl} alt={item.name} className="w-16 h-16 rounded-md object-cover"/>
                                            <div>
                                                <h4 className="font-semibold text-stone-800">{item.name}</h4>
                                                <p className="text-sm text-stone-500">{item.details}</p>
                                                <p className="text-sm text-stone-800 font-medium">${item.price.toFixed(2)} x {item.quantity}</p>
                                            </div>
                                        </div>
                                        <button onClick={() => removeFromCart(item.id)} className="text-red-500 hover:text-red-700 text-sm font-semibold">
                                            Quitar
                                        </button>
                                    </div>
                                ))}
                            </div>

                            <div className="border-t border-stone-200 pt-4 flex justify-between items-center font-bold text-xl">
                                <span className="text-stone-800">Total</span>
                                <span className="text-emerald-800">${totalPrice.toFixed(2)}</span>
                            </div>

                            <div className="mt-8">
                                <h3 className="text-2xl font-['Cormorant_Garamond'] text-stone-800 font-bold mb-4">Información de Pago</h3>
