                                                <h4 className="font-semibold text-base-text">{item.name}</h4>
                                                <p className="text-sm text-detail">{item.details}</p>
                                                <p className="text-sm text-base-text font-medium">${item.price.toFixed(2)} x {item.quantity}</p>
