            </div>
          </div>
          <div className="bg-white/60 p-8 rounded-lg shadow-xl border border-black/5">
            <form onSubmit={handleSubmit} className="space-y-4">
              {/* Honeypot field for spam protection */}
              <input type="text" name="honeypot" value={formState.honeypot} onChange={handleInputChange} style={{ position: 'absolute', left: '-5000px' }} aria-hidden="true" tabIndex={-1} />

