    baseSpring?: number;
    baseFriction?: number;
    baseThickness?: number;
    offsetFactor?: number;
    maxAge?: number;
    pointCount?: number;
    speedMultiplier?: number;
    enableFade?: boolean;
    enableShaderEffect?: boolean;
    effectAmplitude?: number;
    backgroundColor?: [number, number, number, number];
