    updateKeywords();
    initFramebuffers();
    let lastUpdateTime = Date.now();
    let colorUpdateTimer = 0.0;
    updateFrame();

    function updateFrame() {
        if (!isActive) return;
        const dt = calcDeltaTime();
        if (resizeCanvas()) initFramebuffers();
        updateColors(dt);
        applyInputs();
        if (!config.PAUSED) step(dt);
        render(null);
        animationFrameId.current = requestAnimationFrame(updateFrame);
    }

    function calcDeltaTime() { let now = Date.now(); let dt = (now - lastUpdateTime) / 1000; dt = Math.min(dt, 0.016666); lastUpdateTime = now; return dt; }
    function resizeCanvas() { let width = scaleByPixelRatio(canvas.clientWidth); let height = scaleByPixelRatio(canvas.clientHeight); if (canvas.width !== width || canvas.height !== height) { canvas.width = width; canvas.height = height; return true; } return false; }
    function updateKeywords() { let displayKeywords = []; if (config.SHADING) displayKeywords.push('SHADING'); displayMaterial.setKeywords(displayKeywords); }
    function updateColors(dt: number) { colorUpdateTimer += dt * config.COLOR_UPDATE_SPEED; if (colorUpdateTimer >= 1) { colorUpdateTimer = wrap(colorUpdateTimer, 0, 1); pointers.forEach(p => { p.color = generateColor(); }); } }
    function applyInputs() { pointers.forEach(p => { if (p.moved) { p.moved = false; splatPointer(p); } }); }
    function step(dt: number) { gl.disable(gl.BLEND); curlProgram.bind(); gl.uniform2f(curlProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); gl.uniform1i(curlProgram.uniforms!.uVelocity, velocity.read.attach(0)); blit(curl); vorticityProgram.bind(); gl.uniform2f(vorticityProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); gl.uniform1i(vorticityProgram.uniforms!.uVelocity, velocity.read.attach(0)); gl.uniform1i(vorticityProgram.uniforms!.uCurl, curl.attach(1)); gl.uniform1f(vorticityProgram.uniforms!.curl, config.CURL); gl.uniform1f(vorticityProgram.uniforms!.dt, dt); blit(velocity.write); velocity.swap(); divergenceProgram.bind(); gl.uniform2f(divergenceProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); gl.uniform1i(divergenceProgram.uniforms!.uVelocity, velocity.read.attach(0)); blit(divergence); clearProgram.bind(); gl.uniform1i(clearProgram.uniforms!.uTexture, pressure.read.attach(0)); gl.uniform1f(clearProgram.uniforms!.value, config.PRESSURE); blit(pressure.write); pressure.swap(); pressureProgram.bind(); gl.uniform2f(pressureProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); gl.uniform1i(pressureProgram.uniforms!.uDivergence, divergence.attach(0)); for (let i = 0; i < config.PRESSURE_ITERATIONS; i++) { gl.uniform1i(pressureProgram.uniforms!.uPressure, pressure.read.attach(1)); blit(pressure.write); pressure.swap(); } gradienSubtractProgram.bind(); gl.uniform2f(gradienSubtractProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); gl.uniform1i(gradienSubtractProgram.uniforms!.uPressure, pressure.read.attach(0)); gl.uniform1i(gradienSubtractProgram.uniforms!.uVelocity, velocity.read.attach(1)); blit(velocity.write); velocity.swap(); advectionProgram.bind(); gl.uniform2f(advectionProgram.uniforms!.texelSize, velocity.texelSizeX, velocity.texelSizeY); if (!ext.supportLinearFiltering) gl.uniform2f(advectionProgram.uniforms!.dyeTexelSize, velocity.texelSizeX, velocity.texelSizeY); let velocityId = velocity.read.attach(0); gl.uniform1i(advectionProgram.uniforms!.uVelocity, velocityId); gl.uniform1i(advectionProgram.uniforms!.uSource, velocityId); gl.uniform1f(advectionProgram.uniforms!.dt, dt); gl.uniform1f(advectionProgram.uniforms!.dissipation, config.VELOCITY_DISSIPATION); blit(velocity.write); velocity.swap(); if (!ext.supportLinearFiltering) gl.uniform2f(advectionProgram.uniforms!.dyeTexelSize, dye.texelSizeX, dye.texelSizeY); gl.uniform1i(advectionProgram.uniforms!.uVelocity, velocity.read.attach(0)); gl.uniform1i(advectionProgram.uniforms!.uSource, dye.read.attach(1)); gl.uniform1f(advectionProgram.uniforms!.dissipation, config.DENSITY_DISSIPATION); blit(dye.write); dye.swap(); }
    function render(target: any) { if (config.TRANSPARENT) { gl.blendFunc(gl.ONE, gl.ONE_MINUS_SRC_ALPHA); gl.enable(gl.BLEND); } else { gl.clearColor(config.BACK_COLOR.r, config.BACK_COLOR.g, config.BACK_COLOR.b, 1.0); gl.clear(gl.COLOR_BUFFER_BIT); } drawDisplay(target); }
