    function splat(x: number, y: number, dx: number, dy: number, color: { r: number, g: number, b: number }) { splatProgram.bind(); gl.uniform1i(splatProgram.uniforms!.uTarget, velocity.read.attach(0)); gl.uniform1f(splatProgram.uniforms!.aspectRatio, canvas.width / canvas.height); gl.uniform2f(splatProgram.uniforms!.point, x, y); gl.uniform3f(splatProgram.uniforms!.color, dx, dy, 0.0); gl.uniform1f(splatProgram.uniforms!.radius, correctRadius(config.SPLAT_RADIUS / 100.0)); blit(velocity.write); velocity.swap(); gl.uniform1i(splatProgram.uniforms!.uTarget, dye.read.attach(0)); gl.uniform3f(splatProgram.uniforms!.color, color.r, color.g, color.b); blit(dye.write); dye.swap(); }
    function correctRadius(radius: number) { let aspectRatio = canvas.width / canvas.height; if (aspectRatio > 1) radius *= aspectRatio; return radius; }
    function updatePointerMoveData(pointer: Pointer, posX: number, posY: number) { pointer.prevTexcoordX = pointer.texcoordX; pointer.prevTexcoordY = pointer.texcoordY; pointer.texcoordX = posX / canvas.width; pointer.texcoordY = 1.0 - posY / canvas.height; pointer.deltaX = correctDeltaX(pointer.texcoordX - pointer.prevTexcoordX); pointer.deltaY = correctDeltaY(pointer.texcoordY - pointer.prevTexcoordY); pointer.moved = Math.abs(pointer.deltaX) > 0 || Math.abs(pointer.deltaY) > 0; }
    function correctDeltaX(delta: number) { let aspectRatio = canvas.width / canvas.height; if (aspectRatio < 1) delta *= aspectRatio; return delta; }
