    function splat(x: number, y: number, dx: number, dy: number, color: { r: number, g: number, b: number }) { splatProgram.bind(); gl.uniform1i(splatProgram.uniforms!.uTarget, velocity.read.attach(0)); gl.uniform1f(splatProgram.uniforms!.aspectRatio, canvas.width / canvas.height); gl.uniform2f(splatProgram.uniforms!.point, x, y); gl.uniform3f(splatProgram.uniforms!.color, dx, dy, 0.0); gl.uniform1f(splatProgram.uniforms!.radius, correctRadius(config.SPLAT_RADIUS / 100.0)); blit(velocity.write); velocity.swap(); gl.uniform1i(splatProgram.uniforms!.uTarget, dye.read.attach(0)); gl.uniform3f(splatProgram.uniforms!.color, color.r, color.g, color.b); blit(dye.write); dye.swap(); }
