            { r: 0.96, g: 0.94, b: 0.90 }, // Base (Warm White)
            { r: 0.8, g: 0.5, b: 0.3 },   // Terracotta/Ochre
            { r: 0.9, g: 0.7, b: 0.4 },   // Gold Accent
        ];
        const color = clickPalette[Math.floor(Math.random() * clickPalette.length)];
        const dx = 1500 * (Math.random() - 0.5);
        const dy = 1500 * (Math.random() - 0.5);
