import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

// Fix for missing R3F types by augmenting the global JSX namespace
declare global {
  namespace JSX {
    interface IntrinsicElements {
      mesh: any;
      planeGeometry: any;
      shaderMaterial: any;
    }
  }
}

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = `
  uniform vec2 u_mouse;
  uniform float u_time;
  uniform float u_click;
  varying vec2 vUv;

  // 2D Random
  float random (vec2 st) {
      return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
  }

  // 2D Noise
  float noise (vec2 st) {
      vec2 i = floor(st);
      vec2 f = fract(st);
      float a = random(i);
      float b = random(i + vec2(1.0, 0.0));
      float c = random(i + vec2(0.0, 1.0));
      float d = random(i + vec2(1.0, 1.0));
      vec2 u = f*f*(3.0-2.0*f);
      return mix(a, b, u.x) + (c - a)* u.y * (1.0 - u.x) + (d - b) * u.y * u.x;
  }

  void main() {
    vec2 pos = vUv - u_mouse;
    float dist = length(pos);

    // Ink trail effect
    float noise_val = noise(vUv * 5.0 + u_time * 0.2);
    float ink_trail = smoothstep(0.1, 0.0, dist - noise_val * 0.05);
    vec3 trail_color = vec3(0.72, 0.60, 0.43) * 0.4; // Dim accent color

    // Click splash effect
    float click_wave = sin(u_click * 10.0 - dist * 30.0) / 10.0; // Ripple
    float click_effect = smoothstep(0.2, 0.0, dist) * (1.0 - u_click) * 2.0;
    click_effect *= click_wave + 0.5;
    vec3 click_color = vec3(0.96, 0.94, 0.90); // Warm white color

    // Combine effects
    vec3 color = mix(vec3(0.0), trail_color, ink_trail);
    color = mix(color, click_color, click_effect);

    float alpha = max(ink_trail, click_effect * 0.5);

    gl_FragColor = vec4(color, alpha * 0.8);
  }
`;

const SplashCursorR3F: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const { viewport } = useThree();
  const uniforms = useMemo(() => ({
    u_time: { value: 0 },
    u_mouse: { value: new THREE.Vector2(0, 0) },
    u_click: { value: 1.0 }, // 0.0 on click, animates to 1.0
  }), []);

  useEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      if (uniforms.u_mouse) {
        uniforms.u_mouse.value.x = (event.clientX / window.innerWidth);
        uniforms.u_mouse.value.y = 1.0 - (event.clientY / window.innerHeight);
      }
    };

    const handleMouseDown = () => {
        if(uniforms.u_click) {
            uniforms.u_click.value = 0.0;
        }
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
    };
  }, [uniforms.u_mouse, uniforms.u_click]);

  useFrame((state) => {
    const { clock } = state;
    if (meshRef.current) {
      (meshRef.current.material as THREE.ShaderMaterial).uniforms.u_time.value = clock.getElapsedTime();
      if ((meshRef.current.material as THREE.ShaderMaterial).uniforms.u_click.value < 1.0) {
        (meshRef.current.material as THREE.ShaderMaterial).uniforms.u_click.value += 0.02; // Animation speed
      }
    }
  });

  return (
    <mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
      <planeGeometry args={[1, 1]} />
      <shaderMaterial
        uniforms={uniforms}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        transparent
        depthTest={false}
