import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { useTexture } from '@react-three/drei';
import * as THREE from 'three';

// Fix for missing R3F types by augmenting the react module
declare module 'react' {
  namespace JSX {
    interface IntrinsicElements {
      mesh: any;
      planeGeometry: any;
      shaderMaterial: any;
    }
  }
}

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = `
  uniform sampler2D uTexture;
  uniform vec2 uMouse;
  uniform float uHover;
  uniform float uTime;
  varying vec2 vUv;

  void main() {
    vec2 uv = vUv;

    // Calculate distance from mouse for ripple effect
    float dist = distance(uv, uMouse);

    // Create a wave that emanates from the mouse position
    float wave = sin(dist * 25.0 - uTime * 3.0) * 0.02;

    // Apply distortion only when hovering
    uv.x += wave * uHover;
    uv.y += wave * uHover;

    vec4 color = texture2D(uTexture, uv);

    gl_FragColor = color;
  }
`;

interface R3FImagePlaneProps {
  imageUrl: string;
}

const R3FImagePlane: React.FC<R3FImagePlaneProps> = ({ imageUrl }) => {
  const meshRef = useRef<THREE.Mesh>(null!);
  const [hovered, setHovered] = useState(false);

  // Use useTexture from drei for better loading handling
  const texture = useTexture(imageUrl);

  const uniforms = useMemo(() => ({
    uTexture: { value: texture },
    uMouse: { value: new THREE.Vector2(0.5, 0.5) },
    uHover: { value: 0.0 },
    uTime: { value: 0.0 },
  }), [texture]);

  useFrame((state) => {
    const { clock } = state;
    if (meshRef.current) {
        (meshRef.current.material as THREE.ShaderMaterial).uniforms.uTime.value = clock.getElapsedTime();
        (meshRef.current.material as THREE.ShaderMaterial).uniforms.uHover.value = THREE.MathUtils.lerp(
            (meshRef.current.material as THREE.ShaderMaterial).uniforms.uHover.value,
            hovered ? 1.0 : 0.0,
            0.1
        );
    }
  });

  return (
    <mesh
      ref={meshRef}
      scale={[1.5, 2, 1]} // Scale to fit the 3:4 aspect ratio container
      onPointerOver={(e) => {
        setHovered(true);
      }}
      onPointerOut={() => {
        setHovered(false);
      }}
      onPointerMove={(e) => {
        // e.uv is the texture coordinate of the intersection point
        if (e.uv) {
          uniforms.uMouse.value.x = e.uv.x;
          uniforms.uMouse.value.y = e.uv.y;
        }
      }}
    >
      <planeGeometry args={[1, 1]} />
      <shaderMaterial
        uniforms={uniforms}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
      />
    </mesh>
  );
};

