const Header: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const { cart, toggleCheckoutModal, navigate } = useContext(CartContext);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavigate = (page: string) => {
    navigate(page);
    setIsOpen(false);
  };

  // Ultra-minimalist header transition
  const headerClasses = `fixed top-0 w-full z-50 transition-all duration-500 ease-in-out ${
    scrolled 
      ? 'bg-white/90 backdrop-blur-md py-4 shadow-sm border-b border-stone-100' 
      : 'bg-transparent py-6 border-b border-white/10'
  }`;

  const textClasses = scrolled ? 'text-stone-800' : 'text-white';
  const logoClasses = `text-2xl tracking-tighter font-heading font-semibold transition-colors duration-300 ${textClasses}`;

  // Link styles: Uppercase, small text, wide tracking
  const linkClasses = `text-xs font-bold uppercase tracking-[0.15em] hover:text-accent transition-colors duration-300 ${textClasses}`;

  return (
    <header className={headerClasses}>
      <div className="container mx-auto px-8 flex justify-between items-center">

        {/* Logo */}
        <a href="#" onClick={(e) => { e.preventDefault(); handleNavigate('home'); }} className={logoClasses}>
          INNER SPIRIT
        </a>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center space-x-10">
          {navLinks.map((link) => (
            <a 
              key={link.page} 
              href={`#${link.page}`} 
              onClick={(e) => { e.preventDefault(); handleNavigate(link.page); }} 
              className={linkClasses}
            >
              {link.label}
            </a>
          ))}

          <button onClick={toggleCheckoutModal} className={`relative group ${textClasses}`} aria-label="Carrito">
            <span className="group-hover:text-accent transition-colors duration-300">
                <ShoppingCartIcon />
            </span>
            {totalItems > 0 && (
              <span className="absolute -top-1 -right-1 bg-accent text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                {totalItems}
              </span>
            )}
          </button>
        </nav>

        {/* Mobile Menu Button */}
        <div className="md:hidden flex items-center space-x-6">
           <button onClick={toggleCheckoutModal} className={`relative ${textClasses}`}>
            <ShoppingCartIcon />
            {totalItems > 0 && (
              <span className="absolute -top-1 -right-1 bg-accent text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center">
                {totalItems}
              </span>
            )}
          </button>
          <button onClick={() => setIsOpen(!isOpen)} className={textClasses} aria-label="Menú">
             <div className="space-y-1.5 w-6">
                <span className={`block w-full h-0.5 bg-current transition-transform duration-300 ${isOpen ? 'rotate-45 translate-y-2' : ''}`}></span>
                <span className={`block w-full h-0.5 bg-current transition-opacity duration-300 ${isOpen ? 'opacity-0' : ''}`}></span>
                <span className={`block w-full h-0.5 bg-current transition-transform duration-300 ${isOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>
             </div>
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={`fixed inset-0 bg-[#F5F0E6] z-40 flex flex-col items-center justify-center transition-opacity duration-500 ${isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}>
          <nav className="flex flex-col items-center space-y-8">
            {navLinks.map((link) => (
              <a 
                key={link.page} 
                href={`#${link.page}`} 
                onClick={(e) => { e.preventDefault(); handleNavigate(link.page); }} 
                className="text-2xl font-heading text-stone-800 hover:text-accent transition-colors"
              >
                {link.label}
              </a>
            ))}
          </nav>
      </div>
    </header>
  );
};

export default Header;

