                className={`text-4xl font-heading text-stone-800 hover:text-accent transition-transform duration-500 ${isOpen ? 'translate-y-0 opacity-100' : 'translate-y-8 opacity-0'}`}
                style={{ transitionDelay: `${idx * 50}ms` }}
              >
                {link.label}
              </a>
            ))}
          </nav>
      </div>
    </header>
  );
};

